#!/usr/bin/env python3
"""Parse each plan's `## Vault integration` table into a unified TSV.

Run from repo root:
    python3 docs/superpowers/plans/2026-04-18-e2e-walkthrough/coverage/_build-tsv.py

Emits vault-integration.tsv v2 (overwrites).
"""
from __future__ import annotations
import re
from pathlib import Path

ROOT = Path(__file__).resolve().parents[1]
OUT = ROOT / "coverage/vault-integration.tsv"

HEADER = [
    "# Vault Integration Coverage v2 — generated by coverage/_build-tsv.py",
    "# Source: each plan's `## Vault integration (added 2026-04-19)` table",
    "# Columns: plan_file\ttask_id\tinsertion_site\tvault_slug\tstatus",
    "# Status legend: planned | seeded-inbox | extracted | consumed | verified | ✅ existing | 🟡 seed gap",
    "#",
    "plan_file\ttask_id\tinsertion_site\tvault_slug\tstatus",
]

TABLE_RE = re.compile(
    r"^## Vault integration[^\n]*\n"  # section header
    r"(?:(?!\n## )[\s\S])*?"            # anything (non-greedy) until next ##
    r"\n### Planned insertions\s*\n\s*\n"
    r"\| Task \| Insertion site \| Target vault slug \| Status \|\s*\n"
    r"\|[^\n]+\|\s*\n"                   # separator row
    r"((?:\|[^\n]+\|\s*\n)+)",           # data rows
    re.MULTILINE,
)


def parse_plan(p: Path) -> list[tuple[str, str, str, str, str]]:
    text = p.read_text()
    m = TABLE_RE.search(text)
    if not m:
        return []
    rows = []
    for line in m.group(1).strip().splitlines():
        parts = [c.strip() for c in line.strip("|").split("|")]
        if len(parts) < 4:
            continue
        task, site, slug, status = parts[:4]
        # slug may contain backticks / comma-separated — keep as-is
        rows.append((p.name, task, site, slug, status))
    return rows


def main() -> int:
    plans = sorted(ROOT.glob("??-*.md"))
    all_rows: list[tuple[str, str, str, str, str]] = []
    for p in plans:
        all_rows.extend(parse_plan(p))
    lines = list(HEADER)
    for r in all_rows:
        lines.append("\t".join(r))
    OUT.write_text("\n".join(lines) + "\n")
    print(f"wrote {len(all_rows)} rows across {len(plans)} plans → {OUT}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
